const todoList = document.getElementById('todo-list');

// A single listener handles all clicks inside the list
todoList.addEventListener('click', (event) => {
  // Ensure we only react if an actual list item was clicked
  if (event.target.tagName === 'LI') {
    event.target.classList.toggle('task-completed');
    console.log(`Toggled status for: ${event.target.textContent}`);
  }
});

